-- ============================================================
-- 0019 — Import member hours from "Janyaa Member Hours.xlsx" (one-time data load)
--   Sets each member's complete past-hours history from the spreadsheet (exact
--   per-member totals), linking event rows to the matching past event by date.
--   Sets the hours cutoff so old sign-ups stop double-counting, and materializes
--   Rohan's existing sign-up hours (he had no spreadsheet tab) so he keeps them.
--   Idempotent: clears prior source='import' rows before reloading.
-- ============================================================
delete from public.hours_grants where source = 'import';

update public.club_settings set hours_cutoff_date = current_date where id;


-- Rohan Yarrakonda has no spreadsheet tab; keep his current sign-up hours by
-- materializing them into the ledger (linked to each event).
select s.member_id, e.hours, 'import', e.date, e.name, e.id
from public.event_signups s join public.events e on e.id = s.event_id
where s.member_id = '0cc7140d-dc79-4433-b1a4-191db040de1a' and e.date is not null and e.date < current_date;
